import { Intent } from './intent';
import { IntentPayload } from './intent-payload';
import { PathChangeHandler } from './path-change-handler';
import { SendIntentOptions } from '../send-intent';
import { BuiltinTypes } from './builtin/builtin-types';
import { IntentResponseEnvelope, SendIntentWithResponseOptions, Response } from '../send-intent-with-response';
/** @ignore */
export interface DtRuntimeNavigation {
    getIntent(): Intent | null;
    getIntentLink(intentPayload: IntentPayload): string;
    getIntentLink(intentPayload: IntentPayload, appId: string, intentId: string): string;
    sendIntent(intentPayload: IntentPayload): void;
    sendIntent<T extends IntentPayload = IntentPayload>(intentPayload: T, sendIntentOptions: SendIntentOptions<T>): void;
    /**
     * @deprecated
     */
    sendIntent(intentPayload: IntentPayload, recommendedAppId: string, recommendedIntentId: string): void;
    sendIntentWithResponse<T extends BuiltinTypes | string>(intentPayload: IntentPayload, sendIntentWithResponseOptions: SendIntentWithResponseOptions<T>): Promise<Response<T>>;
    sendIntentWithResponseV2<T extends BuiltinTypes | string>(intentPayload: IntentPayload, sendIntentWithResponseOptions: SendIntentWithResponseOptions<T>): Promise<IntentResponseEnvelope<T>>;
    openApp(appId: string, pageToken?: string | undefined): void;
    getAppLink(appId: string, pageToken?: string | undefined): string;
    setPathChangeHandler(handler: PathChangeHandler): void;
    getDocumentLink(documentId: string): string;
    openDocument(documentId: string): void;
}
